def get_all_prompts() -> list[dict]:
    return SEED_PROMPTS


def get_by_category(category: str) -> list[dict]:
    return [p for p in SEED_PROMPTS if p["category"] == category]


def get_categories() -> list[str]:
    return sorted(set(p["category"] for p in SEED_PROMPTS))


if __name__ == "__main__":
    cats = get_categories()
    print(f"Total prompts: {len(SEED_PROMPTS)}")
    print(f"Categories ({len(cats)}): {', '.join(cats)}")
    for cat in cats:
        prompts = get_by_category(cat)
        print(f"  {cat}: {len(prompts)} prompts")
